<div id="LC206" class="react-code-text react-code-line-contents-no-virtualization react-file-line html-div ">    updated_at     <span class="pl-k">TIMESTAMP</span> DEFAULT <span class="pl-c1">CURRENT_TIMESTAMP</span> <span class="pl-k">ON</span> <span class="pl-k">UPDATE</span> <span class="pl-c1">CURRENT_TIMESTAMP</span>,</div>
<div id="LC207" class="react-code-text react-code-line-contents-no-virtualization react-file-line html-div ">
</div>
