<div id="LC210" class="react-code-text react-code-line-contents-no-virtualization react-file-line html-div ">    <span class="pl-k">CONSTRAINT</span> chk_quarter</div>
<div id="LC211" class="react-code-text react-code-line-contents-no-virtualization react-file-line html-div ">        <span class="pl-k">CHECK</span> (review_quarter BETWEEN <span class="pl-c1">1</span> <span class="pl-k">AND</span> <span class="pl-c1">4</span>),</div>
